function setBytesTransiently(bytes memory _data, bool _takeFeeFromPosition) internal {
    uint256 dataLength = _data.length;

    // ensure data follows abi specification, so length will be multiple of 32 when using abi.encode
    require(dataLength >= 32 && dataLength % 32 == 0);

    // write flag to first slot to indicate if fee is taken from position or EOA/wallet
    uint256 flag = _takeFeeFromPosition ? POSITION_FEE_FLAG : EOA_OR_WALLET_FEE_FLAG;
    assembly {
        tstore(0, flag)
    }

    // write length of _data to second slot
    assembly {
        tstore(1, dataLength)
    }

    // calculate how many slots at full size are we going to use
    uint256 chunks = dataLength / 32;
    uint256 i = 1;
    // write _data split into bytes32 from slot 2 to slot 2+chunks
    for (i; i <= chunks; ++i) {
        uint256 slot = i + 1;
        bytes32 chunk;
        assembly {
            chunk := mload(add(_data, mul(0x20, i))) // chunks are bytes32: _data[0:32] -> _data[32:64] -> etc
            tstore(slot, chunk)
        }
    }
}

function getBytesTransiently() public view returns (bytes memory result) {
    uint256 dataLength;
    // fetch data length from first slot
    assembly {
        dataLength := tload(0)
    }
    // find out how many full size chunks there are
    uint256 chunks = dataLength / 32;
    uint256 i = 1;
    // concat each full size chunk to the result
    for (i; i <= chunks; ++i) {
        bytes32 chunk;
        assembly {
            chunk := tload(i)
        }
        result = bytes.concat(result, chunk);
    }
    uint256 leftover = dataLength % 32;
    // create a bytes consisting only of the leftover information
    if (leftover > 0) {
        bytes32 lastChunk;
        assembly {
            lastChunk := tload(i)
        }
        bytes memory cutChunk = new bytes(leftover);
        for (uint256 j = 0; j < leftover; j++) {
            cutChunk[j] = bytes1(bytes32(lastChunk << (j * 8))); // Shift the bytes32 by 8 bits each time
        }

        result = bytes.concat(result, cutChunk);
    }
}

function assertEqCall(
    address targetA,
    bytes memory callDataA,
    address targetB,
    bytes memory callDataB,
    bool strictRevertData
) internal virtual {
    (bool successA, bytes memory returnDataA) = address(targetA).call(callDataA);
    (bool successB, bytes memory returnDataB) = address(targetB).call(callDataB);

    if (successA && successB) {
        assertEq(returnDataA, returnDataB, "Call return data does not match");
    }

    if (!successA && !successB && strictRevertData) {
        assertEq(returnDataA, returnDataB, "Call revert data does not match");
    }

    if (!successA && successB) {
        emit log("Error: Calls were not equal");
        emit log_named_bytes("  Left call revert data", returnDataA);
        emit log_named_bytes(" Right call return data", returnDataB);
        revert("assertion failed");
    }

    if (successA && !successB) {
        emit log("Error: Calls were not equal");
        emit log_named_bytes("  Left call return data", returnDataA);
        emit log_named_bytes(" Right call revert data", returnDataB);
        revert("assertion failed");
    }
}

function setChain(string memory chainAlias, ChainData memory chain) internal virtual {
    require(
        bytes(chainAlias).length != 0,
        "StdChains setChain(string,ChainData): Chain alias cannot be the empty string."
    );

    require(chain.chainId != 0, "StdChains setChain(string,ChainData): Chain ID cannot be 0.");

    _initializeStdChains();
    string memory foundAlias = _idToAlias[chain.chainId];

    require(
        bytes(foundAlias).length == 0 || keccak256(bytes(foundAlias)) == keccak256(bytes(chainAlias)),
        string(
            abi.encodePacked(
                "StdChains setChain(string,ChainData): Chain ID ",
                vm.toString(chain.chainId),
                " already used by \"",
                foundAlias,
                "\"."
            )
        )
    );

    uint256 oldChainId = _chains[chainAlias].chainId;
    delete _idToAlias[oldChainId];

    _chains[chainAlias] =
        Chain({name: chain.name, chainId: chain.chainId, chainAlias: chainAlias, rpcUrl: chain.rpcUrl});
    _idToAlias[chain.chainId] = chainAlias;
}

function getTokenBalances(address token, address[] memory addresses)
        internal
        virtual
        returns (uint256[] memory balances)
    {
        uint256 tokenCodeSize;
        assembly {
            tokenCodeSize := extcodesize(token)
        }
        require(tokenCodeSize > 0, "StdUtils getTokenBalances(address,address[]): Token address is not a contract.");

        // ABI encode the aggregate call to Multicall3.
        uint256 length = addresses.length;
        IMulticall3.Call[] memory calls = new IMulticall3.Call[](length);
        for (uint256 i = 0; i < length; ++i) {
            // 0x70a08231 = bytes4(keccak256("balanceOf(address)"))
            calls[i] = IMulticall3.Call({target: token, callData: abi.encodeWithSelector(0x70a08231, (addresses[i]))});
        }

        // Make the aggregate call.
        (, bytes[] memory returnData) = StdConstants.MULTICALL3_ADDRESS.aggregate(calls);

        // ABI decode the return data and return the balances.
        balances = new uint256[](length);
        for (uint256 i = 0; i < length; ++i) {
            balances[i] = abi.decode(returnData[i], (uint256));
        }
    }

function executeVirtualOrdersInternal(uint256 blockTimestamp) internal {
    emit Value("executeVirtualOrdersInternal", blockTimestamp);
    if(newSwapsPaused) return; // skip twamm executions
    if(twammUpToDate()) return; // save gas

    LongTermOrdersLib.ExecuteVirtualOrdersResult memory result = LongTermOrdersLib.ExecuteVirtualOrdersResult(
        reserve0,
        reserve1,
        twammReserve0,
        twammReserve1,
        fee
    );

    longTermOrders.executeVirtualOrdersUntilTimestamp(blockTimestamp, result);
    emit Value("twammReserve0", result.newTwammReserve0);

    twammReserve0 = uint112(result.newTwammReserve0);
    twammReserve1 = uint112(result.newTwammReserve1);

    uint112 newReserve0 = uint112(result.newReserve0);
    uint112 newReserve1 = uint112(result.newReserve1);

    uint32 timeElapsed = _getTimeElapsed();
    // update reserve0 and reserve1
    if ( timeElapsed > 0 && (newReserve0 != reserve0 || newReserve1 != reserve1)) {
        _update(newReserve0, newReserve1, reserve0, reserve1, timeElapsed);
    } else {
        reserve0 = newReserve0;
        reserve1 = newReserve1;
    }
}

function allBalances() public view returns (
    uint256 frax_ttl,
    uint256 fxs_ttl,
    uint256 col_ttl, // in native decimals()
    uint256 ttl_val_usd_e18
) {
    // Handle this contract first (amos_array[0])
    uint256[12] memory allocations = showAllocations();
    frax_ttl = allocations[2];
    fxs_ttl = allocations[5];
    col_ttl = allocations[9];
    ttl_val_usd_e18 = allocations[11];

    // [0] will always be this address, so skip it to avoid an infinite loop
    for (uint i = 1; i < amos_array.length; i++){
        // Exclude null addresses and EOAs
        if (amos_array[i] != address(0) && !eoa_amos[amos_array[i]]){
            (
                uint256 frax_bal,
                uint256 fxs_bal,
                uint256 collat_bal,
                uint256 total_val_e18
            ) = ICrossChainAMO(amos_array[i]).allDollarBalances();

            frax_ttl += frax_bal;
            fxs_ttl += fxs_bal;
            col_ttl += collat_bal;
            ttl_val_usd_e18 += total_val_e18;
        }
    }
}

